/**
 * Unit Tests for Rule-Based Scoring Stage
 *
 * Tests the sophisticated lexical pattern matching, bounded aggregation, and scoring logic
 * per SCORING_LOGIC.md "Subtype Scoring Formula" section.
 *
 * Constitutional Compliance:
 * - Law 0: Preserves sophisticated classification engine architecture
 * - Law 1: Comprehensive edge case testing prevents functional harm
 * - Law 2: Tests match implementation requirements exactly
 * - Law 3: Clear, maintainable test structure with explainability validation
 */

import {
  executeRuleScoring,
  RuleScoringStageConfig,
  RuleScoringStageConfigSchema,
} from '../../src/stages/rule-scoring';
import {
  AIPromptSystem,
  AttributeRelevanceMatrix,
  AttributeSystem,
  DomainOverrides,
  DomainResolution,
  EmailMessage,
  JSONSchema,
  MultiLabelPolicy,
  ProcessingConfig,
  ProcessingSettings,
  TopLevelCategory,
} from '../../src/types';
import { createClassificationResult, createClassificationSession } from '../../src/utils/initialization';

// Helper function to set up test session and result
function setupTest() {
  const settings: ProcessingSettings = {
    initialization: {
      applyHardAssertions: true,
      seedCategoryScores: true,
    },
    ruleScoring: {
      useLexicalPatterns: true,
      applySubtypeRules: true,
      boundedAggregation: true,
    },
    attributeProcessing: {
      detectSelfSent: true,
      resolveDomains: true,
      deriveContextFlags: true,
    },
    attributeInfluence: {
      applyBonuses: true,
      applyPenalties: true,
      enforceCaps: true,
    },
    multiLabelSelection: {
      maxLabels: 3,
      minSecondaryConfidence: 0.5,
      allowedCombinations: [],
      confidenceGapMinimum: 0.15,
    },
    aiRouting: {
      highConfidenceThreshold: 0.8,
      aiRequiredThreshold: 0.3,
      skipAiConditions: [],
    },
  };

  const multiLabelPolicy: MultiLabelPolicy = {
    maxTopLevelLabels: 3,
    minConfidenceForAdditional: 0.5,
    allowFinancialActionableCopresence: true,
    allowedCombinations: [],
    exclusions: [],
