describe('AggregationCap Logic (T065)', () => {
  it('should cap category score when it exceeds aggregationCap', () => {
    const highScoreConfig = {
      ...mockConfig,
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Receipt with high score',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  { field: 'subject' as const, operation: 'containsAny' as const, values: ['receipt'], weight: 50 },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Financial and monetary communications',
            decisionCriteria: ['Contains financial transactions'],
          },
        },
      },
      tuningParameters: {
        ...mockConfig.tuningParameters,
        KHigh: 3.0, // High multiplier: 50 * 3.0 = 150
        aggregationCap: 1.0, // Cap at 1.0
      },
    };

    const testEmail = {
      ...mockEmail,
      subject: 'Receipt for purchase',
    };

    const { session, result } = setupTest();
    result.emailId = testEmail.id;
    executeRuleScoring(testEmail, session, result, highScoreConfig);

    const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');

    // Score should be capped at 1.0 despite uncapped score being 150
    expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBe(1.0);

    // Should have rationale about capping
    expect(financialResult?.scoringRationale.some((r) => r.includes('aggregationCap'))).toBe(true);
  });

  it('should not apply cap when score is below aggregationCap', () => {
    const lowScoreConfig = {
      ...mockConfig,
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Receipt with low score',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  { field: 'subject' as const, operation: 'containsAny' as const, values: ['receipt'], weight: 5 },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Financial and monetary communications',
            decisionCriteria: ['Contains financial transactions'],
          },
        },
      },
      tuningParameters: {
        ...mockConfig.tuningParameters,
        KHigh: 0.1, // Low multiplier: 5 * 0.1 = 0.5
        aggregationCap: 1.0, // Cap at 1.0
      },
    };

    const testEmail = {
      ...mockEmail,
      subject: 'Receipt for purchase',
    };

    const { session, result } = setupTest();
    result.emailId = testEmail.id;
    executeRuleScoring(testEmail, session, result, lowScoreConfig);

    const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');

    // Score should be 0.5 (uncapped)
    expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBe(0.5);

    // Should NOT have rationale about capping
    expect(financialResult?.scoringRationale.every((r) => !r.includes('aggregationCap'))).toBe(true);
  });

  it('should apply custom aggregationCap from tuning parameters', () => {
    const customCapConfig = {
      ...mockConfig,
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Receipt',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  { field: 'subject' as const, operation: 'containsAny' as const, values: ['receipt'], weight: 20 },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Financial and monetary communications',
            decisionCriteria: ['Contains financial transactions'],
          },
        },
      },
      tuningParameters: {
        ...mockConfig.tuningParameters,
        KHigh: 1.0, // Multiplier: 20 * 1.0 = 20
        aggregationCap: 10.0, // Custom cap at 10.0
      },
    };

    const testEmail = {
      ...mockEmail,
      subject: 'Receipt for purchase',
    };

    const { session, result } = setupTest();
    result.emailId = testEmail.id;
    executeRuleScoring(testEmail, session, result, customCapConfig);

    // Score should be capped at 10.0 (not 1.0)
    expect(result.scoreBreakdown.categoryScores.financial?.finalScore).toBe(10.0);
  });

  it('should validate aggregationCap schema allows fractional values', () => {
    const fractionalCapConfig = {
      ...mockConfig,
      tuningParameters: {
        ...mockConfig.tuningParameters,
        aggregationCap: 0.75, // Fractional cap
      },
    };

    const result = RuleScoringStageConfigSchema.safeParse(fractionalCapConfig);
    expect(result.success).toBe(true);
  });

  it('should validate aggregationCap schema rejects negative values', () => {
    const negativeCapConfig = {
      ...mockConfig,
      tuningParameters: {
        ...mockConfig.tuningParameters,
        aggregationCap: -1.0, // Invalid negative
      },
    };

    const result = RuleScoringStageConfigSchema.safeParse(negativeCapConfig);
    expect(result.success).toBe(false);
  });

  it('should include aggregationCap in explainability trace when capping occurs', () => {
    const highScoreConfig = {
      ...mockConfig,
      topLevelCategories: {
        financial: {
          description: 'Financial communications',
          subtypes: {
            receipt: {
              description: 'Receipt with high score',
              derived: false,
              parallelSafe: true,
              ruleBasedClassification: {
                highConfidence: [
                  { field: 'subject' as const, operation: 'containsAny' as const, values: ['receipt'], weight: 100 },
                ],
              },
            },
          },
          aiFinalClassification: {
            categoryDescription: 'Financial and monetary communications',
            decisionCriteria: ['Contains financial transactions'],
          },
        },
      },
      tuningParameters: {
        ...mockConfig.tuningParameters,
        KHigh: 2.0, // Multiplier: 100 * 2.0 = 200
        aggregationCap: 1.5, // Cap at 1.5
      },
    };

    const testEmail = {
      ...mockEmail,
      subject: 'Receipt for purchase',
    };

    const { session, result } = setupTest();
    result.emailId = testEmail.id;
    executeRuleScoring(testEmail, session, result, highScoreConfig);

    const financialResult = result.explainabilityTrace.ruleScoring.find((cat) => cat.categoryCode === 'financial');

    // Should explicitly mention the capping in rationale
    expect(financialResult?.scoringRationale.some((r) => r.includes('Applied aggregationCap'))).toBe(true);
    expect(financialResult?.scoringRationale.some((r) => r.includes('200.00 → 1.50'))).toBe(true);
  });
});

