      const emptyValuesConfig = {
        ...mockConfig,
        topLevelCategories: {
          testCategory: {
            description: 'Test',
            subtypes: {
              emptyValues: {
                description: 'Test empty values',
                derived: false,
                parallelSafe: true,
                ruleBasedClassification: {
                  highConfidence: [
                    {
                      field: 'subject' as const,
                      operation: 'containsAny' as const,
                      values: [],
                      weight: 10,
