     1→import { z } from 'zod';
     2→import type {
     3→  CategoryRuleResult,
     4→  ClassificationResult,
     5→  ClassificationSession,
     6→  EmailMessage,
     7→  RuleScoringMatch,
     8→  SubtypeDefinition,
     9→  SubtypeScore,
    10→  TopLevelCategory,
    11→} from '../types';
    12→import { RulePatternSchema } from '../config/category-config-schema';
    13→import { ensureCategoryScoreInitialized } from '../utils/initialization';
    14→import { matchRulePattern } from '../utils/rule-matcher';
    15→
    16→/**
    17→ * Rule-Based Scoring Stage
    18→ *
    19→ * Implements lexical pattern matching per SCORING_LOGIC.md "Subtype Scoring Formula" section.
    20→ * Applies rule-based classification patterns with bounded aggregation to prevent score inflation
    21→ * while allowing multiple patterns to contribute to category confidence.
    22→ *
    23→ * CANONICAL SIGNATURE: (email, session, result, config) => void
    24→ *
    25→ * Logic (per SCORING_LOGIC.md):
    26→ * - score(subtype) = sum(high_match_weights) * KHigh
    27→ *                  + sum(medium_match_weights) * KMedium
    28→ *                  + sum(low_match_weights) * KLow
    29→ * - K parameters are MULTIPLIERS applied to sum of ALL tier weights (not topK limits)
    30→ * - Category score = primary + min(secondarySupport, secondarySupportCap)
    31→ * - Uses max of existing score vs aggregated rule score
    32→ * - Mutates result.explainabilityTrace and result.scoreBreakdown instead of returning
    33→ */
    34→
    35→export type SubtypeRuleClassification = NonNullable<SubtypeDefinition['ruleBasedClassification']>;
    36→
    37→export interface RuleScoringStageConfig {
    38→  // Configuration settings for rule scoring behavior
    39→  settings: {
    40→    useLexicalPatterns: boolean;
    41→    applySubtypeRules: boolean;
    42→    boundedAggregation: boolean;
    43→  };
    44→
    45→  // Top-level categories with their subtypes and rules
    46→  topLevelCategories: Record<string, TopLevelCategory>;
    47→
    48→  // Tuning parameters for subtype scoring formula
    49→  tuningParameters: {
    50→    KHigh: number; // Multiplier for sum of high-confidence match weights
    51→    KMedium: number; // Multiplier for sum of medium-confidence match weights
    52→    KLow: number; // Multiplier for sum of low-confidence match weights
    53→    TAIL_DAMPEN: number; // Damping factor for secondary subtype support
    54→    TAIL_RATIO_CAP: number; // Max ratio of tail support to primary score
    55→    aggregationCap: number; // Maximum score a category can reach from rule aggregation (default: 1.0)
    56→  };
    57→}
    58→
    59→// Type re-exports for convenience (actual definitions in types/explainability-trace.ts)
    60→export type { CategoryRuleResult, RuleScoringMatch, SubtypeScore };
    61→
    62→export interface RuleScoringResult {
    63→  categoryResults: CategoryRuleResult[];
    64→  updatedScores: Record<string, number>;
    65→  totalMatches: number;
    66→  categoriesWithRules: number;
    67→  highestRuleScore: number;
    68→  processingDurationMs: number;
    69→}
    70→
    71→export const SubtypeRuleClassificationSchema = z.object({
    72→  highConfidence: z.array(RulePatternSchema).optional(),
    73→  mediumConfidence: z.array(RulePatternSchema).optional(),
    74→  lowConfidence: z.array(RulePatternSchema).optional(),
    75→});
    76→
    77→export const RuleScoringStageConfigSchema = z.object({
    78→  settings: z.object({
    79→    useLexicalPatterns: z.boolean(),
    80→    applySubtypeRules: z.boolean(),
    81→    boundedAggregation: z.boolean(),
    82→  }),
    83→  topLevelCategories: z.record(
    84→    z.object({
    85→      description: z.string(),
    86→      subtypes: z.record(
    87→        z.object({
    88→          description: z.string(),
    89→          ruleBasedClassification: SubtypeRuleClassificationSchema.optional(),
    90→          derived: z.boolean().optional(),
    91→          derivationLogic: z.string().optional(),
    92→        })
    93→      ),
    94→    })
    95→  ),
    96→  tuningParameters: z.object({
    97→    KHigh: z.number().min(0), // Allow fractional multipliers (e.g., 1.0, 0.7)
    98→    KMedium: z.number().min(0), // Allow fractional multipliers
    99→    KLow: z.number().min(0), // Allow fractional multipliers
   100→    TAIL_DAMPEN: z.number().min(0).max(1),
   101→    TAIL_RATIO_CAP: z.number().min(0).max(1),
   102→    aggregationCap: z.number().min(0).default(1.0), // Maximum score from rule aggregation
   103→  }),
   104→});
   105→
   106→/**
   107→ * Execute rule-based scoring stage
   108→ *
   109→ * @param email - Email message to analyze for pattern matches
   110→ * @param session - Classification session batch metadata (canonical signature parameter, not used directly)
   111→ * @param result - Classification result to update (mutated in place)
   112→ * @param config - Rule scoring configuration with pattern hierarchies
   113→ */
   114→export function executeRuleScoring(
   115→  email: EmailMessage,
   116→  _session: ClassificationSession,
   117→  result: ClassificationResult,
   118→  config: RuleScoringStageConfig
   119→): void {
   120→  const startTime = Date.now();
   121→
   122→  console.log(`Rule scoring for email ${email.id}: "${email.subject?.substring(0, 50)}..."`);
   123→
   124→  const { settings, topLevelCategories, tuningParameters } = config;
   125→
   126→  // Early exit if rule scoring is disabled
   127→  if (!settings.useLexicalPatterns || !settings.applySubtypeRules) {
   128→    console.log('Rule scoring disabled by configuration');
   129→    const durationMs = Date.now() - startTime;
